int mn[N][N], mx[N][N], a[N][N];
void solve(int CASE)
{
	int n, m; cin >> n >> m;
	fa(i, 1, n)fa(j, 1, m)cin >> a[i][j];
	if ((n + m - 1) & 1) {
		cout << "NO" << endl;
		return;
	}
	fa(i, 0, n)fa(j, 0, m)mn[i][j] = INF, mx[i][j] = -INF;
	mn[1][1] = mx[1][1] = a[1][1];
	fa(i, 1, n)fa(j, 1, m) {
		if (i == 1 and j == 1)continue;
		mn[i][j] = min(mn[i - 1][j], mn[i][j - 1]) + a[i][j];
		mx[i][j] = max(mx[i - 1][j], mx[i][j - 1]) + a[i][j];
	}
	if (mn[n][m] <= 0 and mx[n][m] >= 0)cout << "YES" << endl;
	else cout << "NO" << endl;
	return;
}
